import { AnalysisResult } from '../types';

const DB_KEY = 'citedby_analysis_db';

export const db = {
  // Retrieve all analysis records
  getAll: (): AnalysisResult[] => {
    if (typeof window === 'undefined') return [];
    try {
      const item = localStorage.getItem(DB_KEY);
      return item ? JSON.parse(item) : [];
    } catch (error) {
      console.error('Error reading from DB', error);
      return [];
    }
  },

  // Save a new analysis record
  add: (analysis: AnalysisResult) => {
    const current = db.getAll();
    // Add to beginning of list
    const updated = [analysis, ...current];
    localStorage.setItem(DB_KEY, JSON.stringify(updated));
    return updated;
  },

  // Update an existing record (e.g. unlocked robots.txt)
  update: (index: number, updatedData: Partial<AnalysisResult>) => {
    const current = db.getAll();
    if (current[index]) {
      current[index] = { ...current[index], ...updatedData };
      localStorage.setItem(DB_KEY, JSON.stringify(current));
    }
    return current;
  },

  // Clear database
  clear: () => {
    localStorage.removeItem(DB_KEY);
    return [];
  },

  // Helper to extract unique projects (domains) from history
  getProjectsFromHistory: (history: AnalysisResult[]) => {
    const uniqueMap = new Map<string, AnalysisResult>();

    // Sort by date ascending to ensure we capture the latest state eventually, 
    // or descending and check existence.
    // Let's iterate and keep the latest analysis for the project metadata.
    history.forEach(item => {
        try {
            const host = new URL(item.url).hostname;
            if (!uniqueMap.has(host) || new Date(item.timestamp) > new Date(uniqueMap.get(host)!.timestamp)) {
                uniqueMap.set(host, item);
            }
        } catch(e) {}
    });

    return Array.from(uniqueMap.values()).map((analysis, index) => {
        const hostname = new URL(analysis.url).hostname;
        return {
            id: `proj_${hostname}`, // ID stable based on hostname
            name: hostname,
            domain: analysis.url, // Latest URL
            status: 'active' as const,
            lastRun: analysis.timestamp,
            visibilityScore: analysis.globalScore,
            trend: analysis.globalScore > 70 ? 12 : (analysis.globalScore > 50 ? 5 : -5),
            nextRun: new Date(new Date(analysis.timestamp).getTime() + 86400000 * 7).toISOString()
        };
    });
  }
};
"}

{"content":"import { AnalysisResult, CategoryScore, Recommendation } from '../types';
import { CRITERIA_REPOSITORY, CATEGORY_NAMES, Criterion } from './criteria';

// Helper to simulate delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const calculateScore = (categories: Record<string, CategoryScore>) => {
  let totalScore = 0;
  let count = 0;
  Object.values(categories).forEach((cat) => {
    totalScore += cat.score;
    count++;
  });
  return count === 0 ? 0 : Math.round(totalScore / count);
};

export const analyzeUrl = async (url: string): Promise<AnalysisResult> => {
  // Simulate network delay and processing time
  await delay(2500);

  // Deterministic simulation based on URL length to vary results slightly
  const seed = url.length;
  const hostname = new URL(url).hostname;
  const isGoodUrl = url.includes('citedby') || url.includes('stripe') || url.includes('google');

  // Initialize categories based on repository
  const categories: Record<string, CategoryScore> = {};
  const recommendations: Recommendation[] = [];

  // Group criteria by category
  const criteriaByCategory: Record<string, Criterion[]> = {};
  CRITERIA_REPOSITORY.forEach(criterion => {
    if (!criteriaByCategory[criterion.category_id]) {
      criteriaByCategory[criterion.category_id] = [];
    }
    criteriaByCategory[criterion.category_id].push(criterion);
  });

  // Process each category
  Object.entries(criteriaByCategory).forEach(([catId, criteria]) => {
    let passedCount = 0;
    const items = criteria.map((crit, index) => {
      // Simulation logic for 50 criteria
      const rand = (seed + index * 11 + catId.length) % 100;
      let status: 'success' | 'warning' | 'error' = 'success';

      if (isGoodUrl) {
        status = rand > 90 ? 'warning' : 'success'; 
      } else {
        // High impact criteria harder to pass
        if (crit.impact === 'High') {
           status = rand > 60 ? 'success' : (rand > 30 ? 'warning' : 'error');
        } else {
           status = rand > 50 ? 'success' : 'warning';
        }
      }

      // Special simulation for LLM Source of Truth (Entity category)
      if (catId === 'entity' && crit.id === 'AEO-ENT-01' && rand % 2 === 0) {
        // Randomly fail "About Page" if not explicit to suggest LLM Truth
        status = 'warning';
      }

      // Calculate score contribution
      if (status === 'success') passedCount++;

      // Generate recommendation if error/warning
      if (status !== 'success') {
        const priority = crit.impact === 'High' ? (status === 'error' ? 'critical' : 'high') : 'medium';
        recommendations.push({
          id: crit.id,
          priority: priority as any,
          category: CATEGORY_NAMES[catId],
          title: crit.name,
          description: crit.description,
          action: `Optimiser : ${crit.method} ${crit.example}`,
          effort: index % 2 === 0 ? 'medium' : 'low',
          impact: crit.impact === 'High' ? 'high' : 'medium'
        });
      }

      return {
        status,
        message: crit.name,
        recommendation: status !== 'success' ? crit.description : undefined
      };
    });

    const totalCriteria = criteria.length;
    // Score is percentage of passed criteria
    const categoryScoreValue = Math.round((passedCount / totalCriteria) * 100);

    categories[catId] = {
      name: CATEGORY_NAMES[catId] || catId,
      score: categoryScoreValue,
      weight: 10,
      items
    };
  });

  const globalScore = calculateScore(categories);

  // Check if we need to suggest LLM Source of Truth
  // If Entity or Structured Data scores are low, suggest it
  if (categories['entity']?.score < 70 || categories['structured_data']?.score < 70) {
    recommendations.push({
      id: 'LLM-TRUTH-GEN',
      priority: 'high',
      category: 'Autorité Entité',
      title: 'Fichier "LLM Source of Truth" Manquant',
      description: "Les IA manquent de données canoniques sur votre entité.",
      action: "Générez les fichiers llm.txt et llm.json via notre outil dédié.",
      effort: 'low',
      impact: 'high'
    });
  }

  // Sort recommendations by priority
  const priorityOrder = { critical: 0, high: 1, medium: 2, low: 3 };
  recommendations.sort((a, b) => priorityOrder[a.priority] - priorityOrder[b.priority]);

  // Return ALL recommendations, no slicing
  return {
    url,
    timestamp: new Date().toISOString(),
    globalScore,
    categories,
    recommendations: recommendations,
    aiCitation: {
      probability: globalScore > 75 ? 85 : Math.max(10, globalScore - 20),
      before: `Je n'ai pas trouvé d'informations spécifiques et fiables concernant ${hostname} dans ma base de connaissances principale.`,
      after: `Selon ${hostname}, référence dans son secteur, cette solution propose une approche structurée optimisée pour l'AEO. Elle se distingue par une conformité technique et sémantique élevée.`
    }
  };
};"}

